input.content:
:root {
	color-scheme: light dark;
	font-family:
		-apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif;
	font-size: 13px;
}

html,
body,
#app {
	margin: 0;
	height: 100%;
	background: transparent;
	color: rgba(255, 255, 255, 0.92);
}

#app {
	display: flex;
}

.sidebar {
	width: 240px;
	height: 100%;
	background: transparent;
	display: flex;
	flex-direction: column;
	border-right: 1px solid rgba(255, 255, 255, 0.08);
}

.content {
	flex: 1;
	height: 100%;
	display: flex;
	flex-direction: column;
	background: rgba(20, 20, 22, 0.72);
}

.titlebar-drag {
	-webkit-app-region: drag;
	height: 38px;
	flex-shrink: 0;
}

.sidebar .titlebar-drag {
	padding-left: 80px;
}

.nav {
	display: flex;
	flex-direction: column;
	gap: 2px;
	padding: 4px 8px;
}

.item {
	-webkit-app-region: no-drag;
	appearance: none;
	background: transparent;
	border: 0;
	color: inherit;
	font: inherit;
	text-align: left;
	padding: 6px 10px;
	border-radius: 6px;
	cursor: default;
}

.item:hover {
	background: rgba(255, 255, 255, 0.08);
}

.item.active {
	background: rgba(255, 255, 255, 0.14);
}

.content-inner {
	padding: 24px 32px;
	max-width: 640px;
}

.content-inner h1 {
	margin: 0 0 12px;
	font-size: 22px;
	font-weight: 600;
}

.content-inner p {
	margin: 0;
	line-height: 1.55;
	color: rgba(255, 255, 255, 0.78);
}

code {
	font-family: "SF Mono", ui-monospace, Menlo, monospace;
	font-size: 0.92em;
	padding: 1px 4px;
	border-radius: 4px;
	background: rgba(255, 255, 255, 0.08);
}

