/usr/bin/python3 -c "
from Quartz import CGWindowListCopyWindowInfo, kCGWindowListOptionOnScreenOnly, kCGNullWindowID
for w in CGWindowListCopyWindowInfo(kCGWindowListOptionOnScreenOnly, kCGNullWindowID):
    if w.get('kCGWindowOwnerPID') == 37769 and w.get('kCGWindowLayer') == 0:
        print(w.get('kCGWindowNumber'), '|', w.get('kCGWindowName'), '|', w.get('kCGWindowOwnerName'))
"

osascript -l JavaScript <<'EOF'
ObjC.import('CoreGraphics');
ObjC.import('Foundation');
var kCGWindowListOptionOnScreenOnly = 1 << 0;
var kCGNullWindowID = 0;
var windows = $.CGWindowListCopyWindowInfo(kCGWindowListOptionOnScreenOnly, kCGNullWindowID);
var n = $.CFArrayGetCount(windows);
var out = [];
for (var i = 0; i < n; i++) {
    var w = ObjC.deepUnwrap($.CFArrayGetValueAtIndex(windows, i));
    if (w.kCGWindowOwnerPID === 37769 && w.kCGWindowLayer === 0) {
        out.push(w.kCGWindowNumber + " " + (w.kCGWindowName || "(untitled)") + " " + JSON.stringify(w.kCGWindowBounds));
    }
}
out.join("\n");
EOF

cat > /tmp/list_windows.js <<'EOF'
ObjC.import('CoreGraphics');
ObjC.import('Foundation');
var opts = 1;  // kCGWindowListOptionOnScreenOnly
var windows = $.CGWindowListCopyWindowInfo(opts, 0);
var n = windows.count;
var out = [];
for (var i = 0; i < n; i++) {
    var w = windows.objectAtIndex(i);
    var pid = w.objectForKey("kCGWindowOwnerPID").js;
    var layer = w.objectForKey("kCGWindowLayer").js;
    var ownerName = w.objectForKey("kCGWindowOwnerName").js;
    if (pid === 37769) {
        var windowNumber = w.objectForKey("kCGWindowNumber").js;
        var bounds = w.objectForKey("kCGWindowBounds");
        out.push(pid + " | " + ownerName + " | layer=" + layer + " | winId=" + windowNumber + " | " + bounds.description.js);
    }
}
out.join("\n");
EOF
osascript -l JavaScript /tmp/list_windows.js

cat > /tmp/find_win.swift <<'EOF'
import Foundation
import CoreGraphics

let targetPid = Int(CommandLine.arguments[1])!
guard let windows = CGWindowListCopyWindowInfo([.optionOnScreenOnly], kCGNullWindowID) as? [[String: Any]] else {
    exit(1)
}
for w in windows {
    guard let pid = w[kCGWindowOwnerPID as String] as? Int, pid == targetPid else { continue }
    let layer = w[kCGWindowLayer as String] as? Int ?? -1
    if layer != 0 { continue }
    let id = w[kCGWindowNumber as String] as? Int ?? -1
    let name = w[kCGWindowName as String] as? String ?? ""
    print("\(id)\t\(name)")
}
EOF
